{
  "name": "Mëso Anglisht - Platforma Shqiptare",
  "description": "A comprehensive English learning platform for Albanian students featuring translation, AI chat, educational games, and administrative controls.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export type ThemeColor = 'blue' | 'red' | 'grey' | 'black' | 'purple' | 'default';

export interface User {
  id: string;
  name: string;
  isAdmin: boolean;
  streak: number;
  lastLogin: string; // ISO date
}

export interface Dialogue {
  id: string;
  title: string;
  content: string;
  audioUrl?: string;
  addedBy: string;
}

export interface Suggestion {
  id: string;
  userId: string;
  userName: string;
  text: string;
  date: string;
}

export interface GameState {
  wordle: { target: string; guesses: string[] };
  hangman: { word: string; guessed: string[]; mistakes: number };
  sentenceBuilder: { original: string; current: string[] };
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const translateText = async (text: string, fromAlbanian: boolean) => {
  const ai = getAI();
  const targetLang = fromAlbanian ? "English" : "Albanian";
  const sourceLang = fromAlbanian ? "Albanian" : "English";

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following ${sourceLang} word or sentence to ${targetLang}: "${text}". Only return the translation, no extra text.`,
  });

  return response.text || "Gabim në përkthim.";
};

export const chatWithAI = async (message: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) => {
  const ai = getAI();
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: "Ti je një mësues ndihmës i gjuhës Angleze për studentët Shqiptarë. Përgjigju në Shqip kur shpjegon rregulla, por inkurajo përdorimin e Anglishtes. Je miqësor dhe edukativ.",
    },
  });

  // Reconstruct history for the SDK if needed, but simplified here
  const response = await chat.sendMessage({ message });
  return response.text || "Më vjen keq, nuk munda të përgjigjem.";
};

export const generateWord = async (difficulty: 'easy' | 'medium' | 'hard' = 'medium') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate one common English word for a learning game (difficulty: ${difficulty}). Return ONLY the word in uppercase.`,
  });
  return response.text?.trim().toUpperCase() || "ENGLISH";
};

export const generateSentence = async () => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate one simple English sentence for a learning exercise. Return ONLY the sentence.`,
  });
  return response.text?.trim() || "The cat is on the mat.";
};

import React, { useState, useEffect } from 'react';
import { generateWord, generateSentence } from '../services/geminiService';

export const Wordle: React.FC = () => {
  const [target, setTarget] = useState('');
  const [guess, setGuess] = useState('');
  const [guesses, setGuesses] = useState<string[]>([]);
  const [status, setStatus] = useState<'playing' | 'won' | 'lost'>('playing');

  const initGame = async () => {
    const word = await generateWord('easy');
    // Ensure 5 letters for wordle-like experience
    setTarget(word.length === 5 ? word : 'LEARN');
    setGuesses([]);
    setGuess('');
    setStatus('playing');
  };

  useEffect(() => { initGame(); }, []);

  const submitGuess = () => {
    if (guess.length !== 5) return;
    const newGuesses = [...guesses, guess.toUpperCase()];
    setGuesses(newGuesses);
    setGuess('');

    if (guess.toUpperCase() === target) {
      setStatus('won');
    } else if (newGuesses.length >= 6) {
      setStatus('lost');
    }
  };

  return (
    <div className="flex flex-col items-center space-y-4 p-6 bg-white rounded-xl shadow-md">
      <h2 className="text-2xl font-bold text-indigo-600">Wordle English</h2>
      <div className="grid grid-rows-6 gap-2">
        {Array.from({ length: 6 }).map((_, i) => {
          const g = guesses[i] || (i === guesses.length ? guess.padEnd(5, ' ') : '     ');
          return (
            <div key={i} className="flex gap-2">
              {g.split('').map((char, j) => {
                let bg = 'bg-gray-100';
                if (guesses[i]) {
                  if (target[j] === char) bg = 'bg-green-500 text-white';
                  else if (target.includes(char)) bg = 'bg-yellow-500 text-white';
                  else bg = 'bg-gray-400 text-white';
                }
                return (
                  <div key={j} className={`w-10 h-10 flex items-center justify-center font-bold border rounded ${bg}`}>
                    {char.trim()}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>
      {status === 'playing' ? (
        <div className="flex gap-2">
          <input
            maxLength={5}
            value={guess}
            onChange={(e) => setGuess(e.target.value)}
            className="border p-2 rounded uppercase w-32 text-center"
            placeholder="5 letra"
          />
          <button onClick={submitGuess} className="bg-indigo-600 text-white px-4 py-2 rounded">Provo</button>
        </div>
      ) : (
        <div className="text-center">
          <p className="mb-2 font-bold">{status === 'won' ? 'Fitove!' : `Humbë! Fjala ishte: ${target}`}</p>
          <button onClick={initGame} className="bg-green-600 text-white px-4 py-2 rounded">Luaj përsëri</button>
        </div>
      )}
    </div>
  );
};

export const Hangman: React.FC = () => {
  const [word, setWord] = useState('');
  const [guessed, setGuessed] = useState<string[]>([]);
  const [mistakes, setMistakes] = useState(0);

  const initGame = async () => {
    const w = await generateWord('medium');
    setWord(w);
    setGuessed([]);
    setMistakes(0);
  };

  useEffect(() => { initGame(); }, []);

  const guessLetter = (l: string) => {
    if (guessed.includes(l) || mistakes >= 6) return;
    setGuessed([...guessed, l]);
    if (!word.includes(l)) setMistakes(mistakes + 1);
  };

  const isWon = word && word.split('').every(l => guessed.includes(l));
  const isLost = mistakes >= 6;

  return (
    <div className="flex flex-col items-center space-y-4 p-6 bg-white rounded-xl shadow-md">
      <h2 className="text-2xl font-bold text-red-600">Hangman (Xhelati)</h2>
      <div className="text-4xl font-mono tracking-widest">
        {word.split('').map((l, i) => (
          <span key={i}>{guessed.includes(l) ? l : '_'} </span>
        ))}
      </div>
      <div className="text-red-500 font-bold">Gabime: {mistakes} / 6</div>
      <div className="flex flex-wrap justify-center gap-1 max-w-xs">
        { "ABCDEFGHIJKLMNOPQRSTUVWXYZ".split('').map(l => (
          <button
            key={l}
            disabled={guessed.includes(l) || isWon || isLost}
            onClick={() => guessLetter(l)}
            className={`w-8 h-8 rounded border ${guessed.includes(l) ? 'bg-gray-300' : 'bg-white hover:bg-gray-100'}`}
          >
            {l}
          </button>
        ))}
      </div>
      {(isWon || isLost) && (
        <div className="text-center">
          <p className="font-bold">{isWon ? 'Urime!' : `Mbaroi! Fjala: ${word}`}</p>
          <button onClick={initGame} className="mt-2 bg-blue-600 text-white px-4 py-2 rounded">Rifillo</button>
        </div>
      )}
    </div>
  );
};

export const SentenceBuilder: React.FC = () => {
  const [sentence, setSentence] = useState('');
  const [words, setWords] = useState<string[]>([]);
  const [selection, setSelection] = useState<string[]>([]);

  const initGame = async () => {
    const s = await generateSentence();
    setSentence(s);
    const split = s.replace(/[.,!?]/g, '').split(' ');
    setWords([...split].sort(() => Math.random() - 0.5));
    setSelection([]);
  };

  useEffect(() => { initGame(); }, []);

  const addWord = (w: string, idx: number) => {
    setSelection([...selection, w]);
    setWords(words.filter((_, i) => i !== idx));
  };

  const removeWord = (w: string, idx: number) => {
    setWords([...words, w]);
    setSelection(selection.filter((_, i) => i !== idx));
  };

  const check = () => {
    const attempt = selection.join(' ');
    const original = sentence.replace(/[.,!?]/g, '');
    if (attempt === original) alert("Saktë!");
    else alert("Provo përsëri.");
  };

  return (
    <div className="flex flex-col items-center space-y-4 p-6 bg-white rounded-xl shadow-md w-full max-w-lg">
      <h2 className="text-2xl font-bold text-green-600">Sentence Builder</h2>
      <div className="w-full min-h-[60px] border-2 border-dashed border-gray-300 rounded-lg p-4 flex flex-wrap gap-2">
        {selection.map((w, i) => (
          <button key={i} onClick={() => removeWord(w, i)} className="bg-green-100 px-3 py-1 rounded border border-green-300">{w}</button>
        ))}
      </div>
      <div className="flex flex-wrap gap-2 justify-center">
        {words.map((w, i) => (
          <button key={i} onClick={() => addWord(w, i)} className="bg-gray-100 px-3 py-1 rounded border border-gray-300 hover:bg-gray-200">{w}</button>
        ))}
      </div>
      <div className="flex gap-2">
        <button onClick={check} className="bg-green-600 text-white px-6 py-2 rounded">Kontrollo</button>
        <button onClick={initGame} className="bg-gray-600 text-white px-6 py-2 rounded">Tjetër</button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeColor, User, Dialogue, Suggestion } from './types';
import { translateText, chatWithAI } from './services/geminiService';
import { Wordle, Hangman, SentenceBuilder } from './components/Games';

// Mock Initial Data
const INITIAL_DIALOGUES: Dialogue[] = [
  { id: '1', title: 'Përshëndetjet (Greetings)', content: 'A: Hello! How are you?\nB: I am fine, thank you. And you?\nA: I am great, thanks for asking.', addedBy: 'Admin' },
  { id: '2', title: 'Në Restorant (At the Restaurant)', content: 'A: Can I have the menu please?\nB: Sure, here it is.\nA: I would like a pizza and some water.', addedBy: 'Admin' }
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<ThemeColor>('default');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [dialogues, setDialogues] = useState<Dialogue[]>(INITIAL_DIALOGUES);
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Persistence
  useEffect(() => {
    const savedTheme = localStorage.getItem('app_theme') as ThemeColor;
    if (savedTheme) setTheme(savedTheme);

    const savedUsers = JSON.parse(localStorage.getItem('app_users') || '[]');
    setAllUsers(savedUsers);

    const savedDialogues = JSON.parse(localStorage.getItem('app_dialogues') || 'null');
    if (savedDialogues) setDialogues(savedDialogues);

    const savedSuggestions = JSON.parse(localStorage.getItem('app_suggestions') || '[]');
    setSuggestions(savedSuggestions);
  }, []);

  useEffect(() => {
    localStorage.setItem('app_theme', theme);
    localStorage.setItem('app_users', JSON.stringify(allUsers));
    localStorage.setItem('app_dialogues', JSON.stringify(dialogues));
    localStorage.setItem('app_suggestions', JSON.stringify(suggestions));
  }, [theme, allUsers, dialogues, suggestions]);

  const login = (name: string, isAdmin = false) => {
    let user = allUsers.find(u => u.name.toLowerCase() === name.toLowerCase());
    if (!user) {
      user = { id: Date.now().toString(), name, isAdmin, streak: 1, lastLogin: new Date().toISOString() };
      setAllUsers([...allUsers, user]);
    } else {
      // Update streak
      const today = new Date().toDateString();
      const last = new Date(user.lastLogin).toDateString();
      if (today !== last) {
        user.streak += 1;
        user.lastLogin = new Date().toISOString();
        setAllUsers(allUsers.map(u => u.id === user?.id ? user! : u));
      }
    }
    setCurrentUser(user);
  };

  const logout = () => setCurrentUser(null);

  const themeClasses = useMemo(() => {
    switch (theme) {
      case 'blue': return 'bg-blue-900 text-white';
      case 'red': return 'bg-red-900 text-white';
      case 'grey': return 'bg-gray-700 text-white';
      case 'black': return 'bg-black text-white';
      case 'purple': return 'bg-purple-900 text-white';
      default: return 'bg-gray-50 text-gray-900';
    }
  }, [theme]);

  if (!currentUser) {
    return <LoginScreen onLogin={login} />;
  }

  return (
    <HashRouter>
      <div className={`min-h-screen transition-all flex flex-col md:flex-row ${themeClasses}`}>
        {/* Sidebar */}
        <aside className="w-full md:w-64 bg-opacity-20 bg-white backdrop-blur-sm border-r border-white border-opacity-10 p-4 space-y-2">
          <div className="mb-8 p-2">
            <h1 className="text-xl font-black uppercase tracking-widest flex items-center gap-2">
              <i className="fas fa-graduation-cap"></i> Mëso Anglisht
            </h1>
            <p className="text-xs opacity-70">Për studentët shqiptarë</p>
          </div>

          <NavLink to="/" icon="translate">Përkthim</NavLink>
          <NavLink to="/dialogues" icon="comments">Dialogje</NavLink>
          <NavLink to="/games" icon="gamepad">Lojëra</NavLink>
          <NavLink to="/chat" icon="robot">Bisedo AI</NavLink>
          <NavLink to="/streak" icon="fire">Progresi</NavLink>
          <NavLink to="/suggestions" icon="lightbulb">Sugjerime</NavLink>
          <NavLink to="/settings" icon="cog">Cilësimet</NavLink>

          {currentUser.isAdmin && (
            <NavLink to="/admin" icon="user-shield" highlight>Admin Panel</NavLink>
          )}

          <button onClick={logout} className="w-full text-left p-3 rounded-lg hover:bg-white hover:bg-opacity-10 transition-colors mt-auto flex items-center gap-3 text-red-400">
            <i className="fas fa-sign-out-alt"></i> Dilni
          </button>
        </aside>

        {/* Main Content */}
        <main className="flex-1 p-4 md:p-8 overflow-y-auto">
          <Routes>
            <Route path="/" element={<PerkthimView />} />
            <Route path="/dialogues" element={<DialoguesView dialogues={dialogues} />} />
            <Route path="/games" element={<GamesView />} />
            <Route path="/chat" element={<ChatView />} />
            <Route path="/streak" element={<StreakView user={currentUser} />} />
            <Route path="/suggestions" element={<SuggestionsView onAdd={(text) => {
              setSuggestions([...suggestions, { id: Date.now().toString(), userId: currentUser.id, userName: currentUser.name, text, date: new Date().toLocaleDateString() }]);
            }} />} />
            <Route path="/settings" element={<SettingsView currentTheme={theme} onThemeChange={setTheme} />} />
            {currentUser.isAdmin && (
              <Route path="/admin" element={
                <AdminView 
                  users={allUsers} 
                  suggestions={suggestions} 
                  onAddDialogue={(d) => setAllUsers(allUsers.map(u => u.name === d.addedBy ? {...u, isAdmin: true} : u))} // Mocking admin add
                  onDialogueAdd={(d) => setDialogues([...dialogues, d])}
                  onMakeAdmin={(name) => {
                    setAllUsers(allUsers.map(u => u.name === name ? {...u, isAdmin: true} : u));
                  }}
                />
              } />
            )}
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

// Sub-components & Views

const NavLink: React.FC<{ to: string, icon: string, children: React.ReactNode, highlight?: boolean }> = ({ to, icon, children, highlight }) => {
  const location = useLocation();
  const active = location.pathname === to;
  return (
    <Link to={to} className={`flex items-center gap-3 p-3 rounded-xl transition-all ${active ? 'bg-white bg-opacity-30 shadow-lg font-bold' : 'hover:bg-white hover:bg-opacity-10'} ${highlight ? 'text-yellow-400 font-bold' : ''}`}>
      <i className={`fas fa-${icon} w-5`}></i>
      {children}
    </Link>
  );
};

