const PerkthimView: React.FC = () => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlbanian, setFromAlbanian] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlbanian);
    setResult(res);
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <h2 className="text-3xl font-bold">Përkthim Falas</h2>
      <div className="bg-white bg-opacity-10 p-6 rounded-2xl backdrop-blur-md shadow-xl border border-white border-opacity-10">
        <div className="flex justify-between items-center mb-4">
          <span className="font-bold">{fromAlbanian ? 'Shqip' : 'Anglisht'}</span>
          <button onClick={() => setFromAlbanian(!fromAlbanian)} className="bg-indigo-500 p-2 rounded-full hover:rotate-180 transition-transform duration-300 text-white">
            <i className="fas fa-exchange-alt"></i>
          </button>
          <span className="font-bold">{fromAlbanian ? 'Anglisht' : 'Shqip'}</span>
        </div>
        <textarea 
          className="w-full p-4 rounded-xl bg-white bg-opacity-10 border border-white border-opacity-20 min-h-[150px] text-lg focus:ring-2 focus:ring-indigo-500 outline-none placeholder-gray-400"
          placeholder="Shkruani këtu..."
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
        <button 
          onClick={handleTranslate} 
          disabled={loading}
          className="w-full mt-4 bg-indigo-500 text-white p-4 rounded-xl font-bold hover:bg-indigo-600 disabled:opacity-50 transition-all flex items-center justify-center gap-2"
        >
          {loading ? <i className="fas fa-circle-notch fa-spin"></i> : 'Përkthe'}
        </button>
      </div>

      {result && (
        <div className="bg-green-500 bg-opacity-20 p-6 rounded-2xl border border-green-500 border-opacity-30 animate-in fade-in slide-in-from-top-4 duration-500">
          <p className="text-sm opacity-60 mb-2">Rezultati:</p>
          <p className="text-2xl font-semibold">{result}</p>
        </div>
      )}
    </div>
  );
};

