          <div className="bg-white text-gray-900 p-8 rounded-2xl max-w-2xl w-full shadow-2xl relative">
            <button onClick={() => setSelected(null)} className="absolute top-4 right-4 text-gray-400 hover:text-red-500"><i className="fas fa-times text-xl"></i></button>
            <h3 className="text-2xl font-bold mb-4">{selected.title}</h3>
            <div className="bg-gray-100 p-6 rounded-xl mb-6 whitespace-pre-wrap italic font-serif text-lg leading-relaxed">
              {selected.content}
            </div>
            <div className="flex gap-4">
              <button onClick={() => speak(selected.content)} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 flex items-center justify-center gap-2">
                <i className="fas fa-play"></i> Dëgjo Prononcimin
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

