const ChatView: React.FC = () => {
  const [messages, setMessages] = useState<{ role: 'user' | 'model', text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const aiRes = await chatWithAI(userMsg, []);
    setMessages(prev => [...prev, { role: 'model', text: aiRes }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[80vh] max-w-4xl mx-auto bg-white bg-opacity-10 rounded-2xl overflow-hidden border border-white border-opacity-10">
      <div className="p-4 bg-indigo-600 bg-opacity-40 border-b border-white border-opacity-10">
        <h2 className="font-bold flex items-center gap-2"><i className="fas fa-robot"></i> Mësuesi AI</h2>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
          <div className="text-center p-8 opacity-50 italic">Përshëndetje! Më pyet çdo gjë rreth gramatikës ose fjalorit të Anglishtes.</div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl ${m.role === 'user' ? 'bg-indigo-600' : 'bg-white bg-opacity-20 border border-white border-opacity-10'}`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && <div className="text-indigo-400 italic">Mësuesi po shkruan...</div>}
      </div>
      <div className="p-4 bg-black bg-opacity-20 flex gap-2">
        <input 
          className="flex-1 bg-white bg-opacity-10 border border-white border-opacity-20 rounded-xl px-4 focus:ring-2 focus:ring-indigo-500 outline-none"
          placeholder="Pyet diçka..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
        />
        <button onClick={sendMessage} className="bg-indigo-600 p-4 rounded-xl hover:bg-indigo-700"><i className="fas fa-paper-plane"></i></button>
      </div>
    </div>
  );
};

