    if (savedTheme) setTheme(savedTheme);
    setAllUsers(JSON.parse(localStorage.getItem('app_users') || '[]'));
    setDialogues(JSON.parse(localStorage.getItem('app_dialogues') || JSON.stringify(INITIAL_DIALOGUES)));
    setSuggestions(JSON.parse(localStorage.getItem('app_suggestions') || '[]'));
  }, []);

  useEffect(() => {
    localStorage.setItem('app_theme', theme);
    localStorage.setItem('app_users', JSON.stringify(allUsers));
    localStorage.setItem('app_dialogues', JSON.stringify(dialogues));
    localStorage.setItem('app_suggestions', JSON.stringify(suggestions));
  }, [theme, allUsers, dialogues, suggestions]);

  const login = (name: string, isAdmin = false) => {
    let user = allUsers.find(u => u.name.toLowerCase() === name.toLowerCase());
    if (!user) {
      user = { 
        id: Date.now().toString(), 
        name, 
        isAdmin, 
        streak: 1, 
        lastLogin: new Date().toISOString(),
        points: 0,
        badges: []
      };
      setAllUsers([...allUsers, user]);
    } else {
      const today = new Date().toDateString();
      const last = new Date(user.lastLogin).toDateString();
      if (today !== last) {
        user.streak += 1;
        user.lastLogin = new Date().toISOString();
        setAllUsers(allUsers.map(u => u.id === user?.id ? user! : u));
      }
    }
    setCurrentUser(user);
  };

  const addPoints = (amount: number) => {
    if (!currentUser) return;
    const updated = { ...currentUser, points: currentUser.points + amount };
    // Check for badges
    if (updated.points >= 100 && !updated.badges.includes('Learner')) updated.badges.push('Learner');
    if (updated.points >= 500 && !updated.badges.includes('Scholar')) updated.badges.push('Scholar');

    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const updateProfile = (proficiency: Proficiency, goal: Goal) => {
    if (!currentUser) return;
    const updated = { ...currentUser, proficiency, goal };
    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const logout = () => setCurrentUser(null);

  const themeClasses = useMemo(() => {
    switch (theme) {
      case 'blue': return 'bg-blue-900 text-white';
      case 'red': return 'bg-red-900 text-white';
      case 'grey': return 'bg-gray-700 text-white';
      case 'black': return 'bg-black text-white';
      case 'purple': return 'bg-purple-900 text-white';
      default: return 'bg-gray-50 text-gray-900';
    }
  }, [theme]);

  if (!currentUser) return <LoginScreen onLogin={login} />;
  if (!currentUser.proficiency) return <ProfileSetup onSave={updateProfile} />;

  return (
    <HashRouter>
      <div className={`min-h-screen transition-all flex flex-col md:flex-row ${themeClasses}`}>
        <aside className="w-full md:w-64 bg-opacity-20 bg-white backdrop-blur-sm border-r border-white border-opacity-10 p-4 space-y-2">
          <div className="mb-4 p-2">
            <h1 className="text-xl font-black uppercase flex items-center gap-2">
              <i className="fas fa-graduation-cap"></i> Mëso Anglisht
            </h1>
            <div className="mt-4 p-3 bg-white bg-opacity-10 rounded-xl">
              <p className="text-sm font-bold">{currentUser.name}</p>
              <p className="text-xs text-yellow-400 font-bold">{currentUser.points} Pikë • {currentUser.streak} 🔥</p>
              <div className="flex gap-1 mt-1">
                {currentUser.badges.map(b => <span key={b} className="text-[10px] bg-indigo-500 px-1 rounded" title={b}>{b}</span>)}
              </div>
            </div>
          </div>

          <NavLink to="/" icon="translate">Përkthim</NavLink>
          <NavLink to="/dialogues" icon="comments">Dialogje</NavLink>
          <NavLink to="/games" icon="gamepad">Lojëra</NavLink>
          <NavLink to="/leaderboard" icon="trophy">Renditja</NavLink>
          <NavLink to="/chat" icon="robot">Bisedo AI</NavLink>
          <NavLink to="/streak" icon="fire">Progresi</NavLink>
          <NavLink to="/suggestions" icon="lightbulb">Sugjerime</NavLink>
          <NavLink to="/settings" icon="cog">Cilësimet</NavLink>

          {currentUser.isAdmin && <NavLink to="/admin" icon="user-shield" highlight>Admin Panel</NavLink>}

          <button onClick={logout} className="w-full text-left p-3 rounded-lg hover:bg-white hover:bg-opacity-10 transition-colors mt-auto flex items-center gap-3 text-red-400">
            <i className="fas fa-sign-out-alt"></i> Dilni
          </button>
        </aside>

        <main className="flex-1 p-4 md:p-8 overflow-y-auto">
          <Routes>
            <Route path="/" element={<PerkthimView onTranslate={() => addPoints(5)} />} />
            <Route path="/dialogues" element={<DialoguesView dialogues={dialogues} level={currentUser.proficiency} />} />
            <Route path="/games" element={<GamesView onWin={addPoints} level={currentUser.proficiency} />} />
            <Route path="/leaderboard" element={<LeaderboardView users={allUsers} />} />
            <Route path="/chat" element={<ChatView level={currentUser.proficiency} />} />
            <Route path="/streak" element={<StreakView user={currentUser} />} />
            <Route path="/suggestions" element={<SuggestionsView suggestions={suggestions} onAdd={(text) => {
              setSuggestions([...suggestions, { id: Date.now().toString(), userId: currentUser.id, userName: currentUser.name, text, date: new Date().toLocaleDateString() }]);
            }} />} />
            <Route path="/settings" element={<SettingsView currentTheme={theme} onThemeChange={setTheme} />} />
            {currentUser.isAdmin && (
              <Route path="/admin" element={
                <AdminView 
                  users={allUsers} 
                  suggestions={suggestions} 
                  onDialogueAdd={(d) => setDialogues([...dialogues, d])}
                  onMakeAdmin={(id) => setAllUsers(allUsers.map(u => u.id === id ? {...u, isAdmin: !u.isAdmin} : u))}
                  onRespondSuggestion={(id, msg) => setSuggestions(suggestions.map(s => s.id === id ? {...s, adminResponse: msg} : s))}
                />
              } />
            )}
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

