const PerkthimView: React.FC<{ onTranslate: () => void }> = ({ onTranslate }) => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlbanian, setFromAlbanian] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlbanian);
    setResult(res);
    onTranslate();
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <h2 className="text-3xl font-bold">Përkthim Falas</h2>
      <div className="bg-white bg-opacity-10 p-6 rounded-2xl border border-white border-opacity-10">
        <div className="flex justify-between items-center mb-4">
          <span className="font-bold">{fromAlbanian ? 'Shqip' : 'Anglisht'}</span>
          <button onClick={() => setFromAlbanian(!fromAlbanian)} className="text-indigo-400"><i className="fas fa-exchange-alt"></i></button>
          <span className="font-bold">{fromAlbanian ? 'Anglisht' : 'Shqip'}</span>
        </div>
        <textarea className="w-full p-4 rounded-xl bg-white bg-opacity-10 border border-white border-opacity-20 min-h-[150px] outline-none" value={text} onChange={e => setText(e.target.value)} />
        <button onClick={handleTranslate} className="w-full mt-4 bg-indigo-500 py-4 rounded-xl font-bold">{loading ? '...' : 'Përkthe'}</button>
      </div>
      {result && <div className="bg-green-500 bg-opacity-20 p-6 rounded-2xl border border-green-500 font-bold text-xl">{result}</div>}
    </div>
  );
};

