const ChatView: React.FC<{ level: Proficiency }> = ({ level }) => {
  const [messages, setMessages] = useState<{ role: string, text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim()) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[70vh] max-w-4xl mx-auto bg-white bg-opacity-10 rounded-2xl overflow-hidden border border-white border-opacity-10">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`p-4 rounded-2xl max-w-[80%] ${m.role === 'user' ? 'bg-indigo-600' : 'bg-white bg-opacity-20'}`}>{m.text}</div>
          </div>
        ))}
        {loading && <p className="italic opacity-50">Duke menduar...</p>}
      </div>
      <div className="p-4 flex gap-2">
        <input className="flex-1 bg-white bg-opacity-10 rounded-xl px-4 border border-white border-opacity-20" value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && send()} />
        <button onClick={send} className="bg-indigo-600 px-6 rounded-xl font-bold">Dërgo</button>
      </div>
    </div>
  );
};

