const AdminView: React.FC<{ 
  users: User[], 
  suggestions: Suggestion[], 
  onDialogueAdd: (d: Dialogue) => void,
  onMakeAdmin: (id: string) => void,
  onRespondSuggestion: (id: string, msg: string) => void
}> = ({ users, suggestions, onDialogueAdd, onMakeAdmin, onRespondSuggestion }) => {
  const [tab, setTab] = useState('users');
  const [newD, setNewD] = useState({ title: '', content: '', level: 'Beginner' as Proficiency });
  const [resp, setResp] = useState<{ [key: string]: string }>({});

  return (
    <div className="max-w-6xl mx-auto space-y-8">
      <div className="flex gap-4">
        {['users', 'dialogues', 'suggestions'].map(t => (
          <button key={t} onClick={() => setTab(t)} className={`px-6 py-2 rounded-xl font-bold uppercase text-xs ${tab === t ? 'bg-indigo-600' : 'bg-white bg-opacity-10'}`}>{t}</button>
        ))}
      </div>

      {tab === 'users' && (
        <div className="bg-white bg-opacity-10 rounded-2xl overflow-hidden border border-white border-opacity-10">
          <table className="w-full text-left">
            <thead className="bg-white bg-opacity-10 font-bold uppercase text-xs">
              <tr><th className="p-4">Studenti</th><th className="p-4">Niveli</th><th className="p-4">Pikë</th><th className="p-4">Roli</th><th className="p-4">Veprime</th></tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u.id} className="border-t border-white border-opacity-5">
                  <td className="p-4 font-bold">{u.name}</td>
                  <td className="p-4">{u.proficiency || 'I pa-vendosur'}</td>
                  <td className="p-4 font-black text-yellow-400">{u.points}</td>
                  <td className="p-4">{u.isAdmin ? 'ADMIN' : 'STUDENT'}</td>
                  <td className="p-4">
                    <button onClick={() => onMakeAdmin(u.id)} className={`text-[10px] px-3 py-1 rounded font-bold ${u.isAdmin ? 'bg-red-500' : 'bg-green-600'}`}>
                      {u.isAdmin ? 'Largo Roli Admin' : 'Bëje Admin'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {tab === 'dialogues' && (
        <div className="bg-white bg-opacity-10 p-6 rounded-2xl space-y-4">
          <h3 className="font-bold">Shto Dialog të Ri</h3>
          <input className="w-full bg-white bg-opacity-10 p-3 rounded-lg border border-white border-opacity-10" placeholder="Titulli" value={newD.title} onChange={e => setNewD({...newD, title: e.target.value})} />
          <textarea className="w-full bg-white bg-opacity-10 p-3 rounded-lg border border-white border-opacity-10 min-h-[100px]" placeholder="Përmbajtja" value={newD.content} onChange={e => setNewD({...newD, content: e.target.value})} />
          <select className="w-full bg-gray-800 p-3 rounded-lg" value={newD.level} onChange={e => setNewD({...newD, level: e.target.value as Proficiency})}>
            <option>Beginner</option><option>Intermediate</option><option>Advanced</option>
          </select>
          <button onClick={() => { onDialogueAdd({ id: Date.now().toString(), ...newD, addedBy: 'Admin' }); alert('Shtuar!'); }} className="bg-indigo-600 px-8 py-3 rounded-xl font-bold">Publiko Dialogun</button>
        </div>
      )}

      {tab === 'suggestions' && (
        <div className="space-y-4">
          {suggestions.map(s => (
            <div key={s.id} className="p-6 bg-white bg-opacity-10 rounded-2xl border border-white border-opacity-10">
              <p className="font-bold mb-2">{s.userName}: <span className="font-normal">{s.text}</span></p>
              {s.adminResponse ? (
                <p className="text-sm italic text-yellow-400">Përgjigjur: {s.adminResponse}</p>
              ) : (
                <div className="flex gap-2 mt-4">
                  <input className="flex-1 bg-white bg-opacity-10 p-2 rounded-lg text-sm" placeholder="Përgjigju..." value={resp[s.id] || ''} onChange={e => setResp({...resp, [s.id]: e.target.value})} />
                  <button onClick={() => onRespondSuggestion(s.id, resp[s.id])} className="bg-indigo-600 px-4 rounded-lg text-xs font-bold">Dërgo</button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

export type ThemeColor = 'blue' | 'red' | 'grey' | 'black' | 'purple' | 'default';
export type Proficiency = 'Beginner' | 'Intermediate' | 'Advanced';
export type Goal = 'Conversational' | 'Business' | 'Exam Prep' | 'Travel';
export type AuthProvider = 'google' | 'email' | 'admin';

export interface User {
  id: string;
  name: string;
  email?: string;
  isAdmin: boolean;
  streak: number;
  lastLogin: string;
  points: number;
  badges: string[];
  proficiency?: Proficiency;
  goal?: Goal;
  authProvider: AuthProvider;
  password?: string; // Only for admins
}

export interface Dialogue {
  id: string;
  title: string;
  content: string;
  audioUrl?: string;
  addedBy: string;
  level: Proficiency;
}

export interface Suggestion {
  id: string;
  userId: string;
  userName: string;
  text: string;
  date: string;
  adminResponse?: string;
}

export interface GameState {
  wordle: { target: string; guesses: string[] };
  hangman: { word: string; guessed: string[]; mistakes: number };
  sentenceBuilder: { original: string; current: string[] };
}

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeColor, User, Dialogue, Suggestion, Proficiency, Goal, AuthProvider } from './types';
import { translateText, chatWithAI } from './services/geminiService';
import { Wordle, Hangman, SentenceBuilder } from './components/Games';

const INITIAL_DIALOGUES: Dialogue[] = [
  { id: '1', title: 'Greetings', content: 'A: Hello! How are you?\nB: I am fine, thank you.', addedBy: 'Admin', level: 'Beginner' },
  { id: '2', title: 'Business Meeting', content: 'A: Let\'s review the quarterly results.\nB: Certainly, the growth is steady.', addedBy: 'Admin', level: 'Advanced' }
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<ThemeColor>('default');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [dialogues, setDialogues] = useState<Dialogue[]>(INITIAL_DIALOGUES);
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);

  useEffect(() => {
    const savedTheme = localStorage.getItem('app_theme') as ThemeColor;
    if (savedTheme) setTheme(savedTheme);
    setAllUsers(JSON.parse(localStorage.getItem('app_users') || '[]'));
    setDialogues(JSON.parse(localStorage.getItem('app_dialogues') || JSON.stringify(INITIAL_DIALOGUES)));
    setSuggestions(JSON.parse(localStorage.getItem('app_suggestions') || '[]'));
  }, []);

  useEffect(() => {
    localStorage.setItem('app_theme', theme);
    localStorage.setItem('app_users', JSON.stringify(allUsers));
    localStorage.setItem('app_dialogues', JSON.stringify(dialogues));
    localStorage.setItem('app_suggestions', JSON.stringify(suggestions));
  }, [theme, allUsers, dialogues, suggestions]);

  const login = (data: { name: string; email?: string; password?: string; provider: AuthProvider; isAdmin: boolean }) => {
    let user = allUsers.find(u => 
      (data.email && u.email === data.email) || 
      (!data.email && u.name.toLowerCase() === data.name.toLowerCase())
    );

    if (data.isAdmin) {
      if (user && user.password !== data.password) {
        alert("Fjalëkalim i pasaktë për administratorin.");
        return;
      }
      if (!user) {
        // First time admin setup or dynamic creation
        user = { 
          id: Date.now().toString(), 
          name: data.name, 
          isAdmin: true, 
          streak: 1, 
          lastLogin: new Date().toISOString(),
          points: 0,
          badges: [],
          authProvider: 'admin',
          password: data.password
        };
        setAllUsers([...allUsers, user]);
      }
    } else {
      if (!user) {
        user = { 
          id: Date.now().toString(), 
          name: data.name, 
          email: data.email,
          isAdmin: false, 
          streak: 1, 
          lastLogin: new Date().toISOString(),
          points: 0,
          badges: [],
          authProvider: data.provider
        };
        setAllUsers([...allUsers, user]);
      }
    }

    // Update streak logic
    const today = new Date().toDateString();
    const last = new Date(user!.lastLogin).toDateString();
    if (today !== last) {
      user!.streak += 1;
      user!.lastLogin = new Date().toISOString();
      setAllUsers(allUsers.map(u => u.id === user?.id ? user! : u));
    }

    setCurrentUser(user!);
  };

  const addPoints = (amount: number) => {
    if (!currentUser) return;
    const updated = { ...currentUser, points: currentUser.points + amount };
    if (updated.points >= 100 && !updated.badges.includes('Learner')) updated.badges.push('Learner');
    if (updated.points >= 500 && !updated.badges.includes('Scholar')) updated.badges.push('Scholar');

    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const updateProfile = (proficiency: Proficiency, goal: Goal) => {
    if (!currentUser) return;
    const updated = { ...currentUser, proficiency, goal };
    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const logout = () => setCurrentUser(null);

  const themeClasses = useMemo(() => {
    switch (theme) {
      case 'blue': return 'bg-blue-900 text-white';
      case 'red': return 'bg-red-900 text-white';
      case 'grey': return 'bg-gray-700 text-white';
      case 'black': return 'bg-black text-white';
      case 'purple': return 'bg-purple-900 text-white';
      default: return 'bg-gray-50 text-gray-900';
    }
  }, [theme]);

  if (!currentUser) return <LoginScreen onLogin={login} />;
  if (!currentUser.proficiency && !currentUser.isAdmin) return <ProfileSetup onSave={updateProfile} />;

  return (
    <HashRouter>
      <div className={`min-h-screen transition-all flex flex-col md:flex-row ${themeClasses}`}>
        <aside className="w-full md:w-64 bg-opacity-20 bg-white backdrop-blur-sm border-r border-white border-opacity-10 p-4 space-y-2">
          <div className="mb-4 p-2">
            <h1 className="text-xl font-black uppercase flex items-center gap-2">
              <i className="fas fa-graduation-cap"></i> Mëso Anglisht
            </h1>
            <div className="mt-4 p-3 bg-white bg-opacity-10 rounded-xl">
              <p className="text-sm font-bold flex items-center gap-2">
                {currentUser.isAdmin && <i className="fas fa-user-shield text-yellow-400"></i>}
                {currentUser.name}
              </p>
              <p className="text-xs text-yellow-400 font-bold">{currentUser.points} Pikë • {currentUser.streak} 🔥</p>
            </div>
          </div>

          <NavLink to="/" icon="translate">Përkthim</NavLink>
          <NavLink to="/dialogues" icon="comments">Dialogje</NavLink>
          <NavLink to="/games" icon="gamepad">Lojëra</NavLink>
          <NavLink to="/leaderboard" icon="trophy">Renditja</NavLink>
          <NavLink to="/chat" icon="robot">Bisedo AI</NavLink>
          <NavLink to="/streak" icon="fire">Progresi</NavLink>
          <NavLink to="/suggestions" icon="lightbulb">Sugjerime</NavLink>
          <NavLink to="/settings" icon="cog">Cilësimet</NavLink>

          {currentUser.isAdmin && <NavLink to="/admin" icon="user-shield" highlight>Admin Panel</NavLink>}

          <button onClick={logout} className="w-full text-left p-3 rounded-lg hover:bg-white hover:bg-opacity-10 transition-colors mt-auto flex items-center gap-3 text-red-400">
            <i className="fas fa-sign-out-alt"></i> Dilni
          </button>
        </aside>

        <main className="flex-1 p-4 md:p-8 overflow-y-auto">
          <Routes>
            <Route path="/" element={<PerkthimView onTranslate={() => addPoints(5)} />} />
            <Route path="/dialogues" element={<DialoguesView dialogues={dialogues} level={currentUser.proficiency || 'Beginner'} />} />
            <Route path="/games" element={<GamesView onWin={addPoints} level={currentUser.proficiency || 'Beginner'} />} />
            <Route path="/leaderboard" element={<LeaderboardView users={allUsers} />} />
            <Route path="/chat" element={<ChatView level={currentUser.proficiency || 'Beginner'} />} />
            <Route path="/streak" element={<StreakView user={currentUser} />} />
            <Route path="/suggestions" element={<SuggestionsView suggestions={suggestions} onAdd={(text) => {
              setSuggestions([...suggestions, { id: Date.now().toString(), userId: currentUser.id, userName: currentUser.name, text, date: new Date().toLocaleDateString() }]);
            }} />} />
            <Route path="/settings" element={<SettingsView currentTheme={theme} onThemeChange={setTheme} />} />
            {currentUser.isAdmin && (
              <Route path="/admin" element={
                <AdminView 
                  users={allUsers} 
                  suggestions={suggestions} 
                  onDialogueAdd={(d) => setDialogues([...dialogues, d])}
                  onMakeAdmin={(id, pass) => setAllUsers(allUsers.map(u => u.id === id ? {...u, isAdmin: !u.isAdmin, password: pass} : u))}
                  onRespondSuggestion={(id, msg) => setSuggestions(suggestions.map(s => s.id === id ? {...s, adminResponse: msg} : s))}
                />
              } />
            )}
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

// UI Components

const LoginScreen: React.FC<{ onLogin: (d: any) => void }> = ({ onLogin }) => {
  const [mode, setMode] = useState<'student' | 'admin'>('student');
  const [studentMethod, setStudentMethod] = useState<'none' | 'email'>('none');
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleGoogleLogin = () => {
    // Simulating Google Auth
    const mockGoogleName = "Student i Google";
    const mockGoogleEmail = "student@gmail.com";
    onLogin({ name: mockGoogleName, email: mockGoogleEmail, provider: 'google', isAdmin: false });
  };

  const handleEmailLogin = () => {
    if (!formData.name || !formData.email) {
      alert("Ju lutem plotësoni emrin dhe emailin.");
      return;
    }
    onLogin({ name: formData.name, email: formData.email, provider: 'email', isAdmin: false });
  };

  const handleAdminLogin = () => {
    if (!formData.name || !formData.password) {
      alert("Ju lutem plotësoni emrin dhe fjalëkalimin.");
      return;
    }
    onLogin({ name: formData.name, password: formData.password, provider: 'admin', isAdmin: true });
  };

  return (
    <div className="min-h-screen bg-indigo-600 flex items-center justify-center p-4 font-sans">
      <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-4 text-indigo-600 text-2xl">
            <i className="fas fa-graduation-cap"></i>
          </div>
          <h1 className="text-2xl font-bold text-gray-800">Mëso Anglisht</h1>
          <p className="text-gray-500 text-sm">Zgjidhni mënyrën e hyrjes</p>
        </div>

        <div className="flex bg-gray-100 p-1 rounded-xl mb-6">
          <button 
            onClick={() => setMode('student')} 
            className={`flex-1 py-2 rounded-lg font-bold text-sm transition-all ${mode === 'student' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-500'}`}
          >
            Student
          </button>
          <button 
            onClick={() => setMode('admin')} 
            className={`flex-1 py-2 rounded-lg font-bold text-sm transition-all ${mode === 'admin' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-500'}`}
          >
            Administrator
          </button>
        </div>

        {mode === 'student' ? (
          <div className="space-y-4">
            {studentMethod === 'none' ? (
              <>
                <button 
                  onClick={handleGoogleLogin}
                  className="w-full flex items-center justify-center gap-3 bg-white border border-gray-300 p-4 rounded-xl hover:bg-gray-50 transition-all font-semibold text-gray-700"
                >
                  <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" className="w-5 h-5" alt="Google" />
                  Hyr me Google
                </button>
                <button 
                  onClick={() => setStudentMethod('email')}
                  className="w-full flex items-center justify-center gap-3 bg-indigo-600 text-white p-4 rounded-xl hover:bg-indigo-700 transition-all font-semibold"
                >
                  <i className="fas fa-envelope"></i>
                  Hyr me Email
                </button>
              </>
            ) : (
              <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2">
                <input 
                  type="text" 
                  placeholder="Emri juaj" 
                  className="w-full p-4 border rounded-xl text-gray-900 outline-none focus:ring-2 focus:ring-indigo-500" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
                <input 
                  type="email" 
                  placeholder="Email adresa" 
                  className="w-full p-4 border rounded-xl text-gray-900 outline-none focus:ring-2 focus:ring-indigo-500" 
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                />
                <button onClick={handleEmailLogin} className="w-full bg-indigo-600 text-white p-4 rounded-xl font-bold">Vazhdo</button>
                <button onClick={() => setStudentMethod('none')} className="w-full text-sm text-gray-500 hover:underline">Kthehu mbrapa</button>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-in fade-in">
            <input 
              type="text" 
              placeholder="Përdoruesi Admin" 
              className="w-full p-4 border rounded-xl text-gray-900 outline-none focus:ring-2 focus:ring-indigo-500" 
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
            />
            <input 
              type="password" 
              placeholder="Fjalëkalimi" 
              className="w-full p-4 border rounded-xl text-gray-900 outline-none focus:ring-2 focus:ring-indigo-500" 
              value={formData.password}
              onChange={e => setFormData({...formData, password: e.target.value})}
            />
            <button onClick={handleAdminLogin} className="w-full bg-indigo-800 text-white p-4 rounded-xl font-bold">Hyr si Admin</button>
            <p className="text-[10px] text-gray-400 text-center italic">Vetëm administratorët e autorizuar mund të hyjnë këtu.</p>
          </div>
        )}
      </div>
    </div>
  );
};

