  const [g, setG] = useState<Goal>('Conversational');
  return (
    <div className="min-h-screen bg-indigo-500 flex items-center justify-center p-4 text-white">
      <div className="bg-white text-gray-900 p-8 rounded-2xl max-w-md w-full shadow-2xl">
        <h2 className="text-2xl font-bold mb-6 text-center">Përshtatni Eksperiencën</h2>
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold mb-1 text-gray-600">Niveli juaj aktual:</label>
            <select value={p} onChange={e => setP(e.target.value as Proficiency)} className="w-full p-3 border rounded-lg bg-gray-50">
              <option>Beginner</option><option>Intermediate</option><option>Advanced</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-bold mb-1 text-gray-600">Qëllimi i mësimit:</label>
            <select value={g} onChange={e => setG(e.target.value as Goal)} className="w-full p-3 border rounded-lg bg-gray-50">
              <option>Conversational</option><option>Business</option><option>Exam Prep</option><option>Travel</option>
            </select>
          </div>
          <button onClick={() => onSave(p, g)} className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold mt-4 hover:bg-indigo-700 transition-all">Fillo udhëtimin tim</button>
        </div>
      </div>
    </div>
