};

const PerkthimView: React.FC<{ onTranslate: () => void }> = ({ onTranslate }) => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlbanian, setFromAlbanian] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlbanian);
    setResult(res);
    onTranslate();
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <h2 className="text-3xl font-bold">Perkthim</h2>
      <div className="bg-white bg-opacity-10 p-6 rounded-2xl border border-white border-opacity-10 backdrop-blur-md shadow-lg">
        <div className="flex justify-between items-center mb-4">
          <div className="flex flex-col items-center">
            <span className="text-xs uppercase opacity-50 mb-1">Nga</span>
            <span className="font-black text-xl">{fromAlbanian ? 'Shqip' : 'Anglisht'}</span>
          </div>
          <button onClick={() => setFromAlbanian(!fromAlbanian)} className="w-12 h-12 rounded-full bg-indigo-500 flex items-center justify-center hover:rotate-180 transition-all duration-500 shadow-lg">
            <i className="fas fa-exchange-alt"></i>
          </button>
          <div className="flex flex-col items-center">
            <span className="text-xs uppercase opacity-50 mb-1">Te</span>
            <span className="font-black text-xl">{fromAlbanian ? 'Anglisht' : 'Shqip'}</span>
          </div>
        </div>
        <textarea 
          className="w-full p-6 rounded-2xl bg-white bg-opacity-5 border border-white border-opacity-20 min-h-[180px] outline-none text-lg resize-none placeholder-gray-400" 
          placeholder="Shkruani fjalën ose fjalinë këtu..." 
          value={text} 
          onChange={e => setText(e.target.value)} 
        />
        <button 
          onClick={handleTranslate} 
          disabled={loading}
          className="w-full mt-4 bg-indigo-500 py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-xl flex items-center justify-center gap-3"
        >
          {loading ? <i className="fas fa-circle-notch fa-spin"></i> : <><i className="fas fa-magic"></i> Përkthe</>}
        </button>
      </div>
      {result && (
        <div className="bg-green-500 bg-opacity-20 p-8 rounded-3xl border-2 border-green-500 animate-in zoom-in duration-300">
          <p className="text-xs uppercase opacity-50 mb-2">Përkthimi i gjetur:</p>
          <p className="font-black text-3xl">{result}</p>
        </div>
      )}
    </div>
  );
};

const DialoguesView: React.FC<{ dialogues: Dialogue[], level: Proficiency }> = ({ dialogues, level }) => {
  const filtered = dialogues.filter(d => d.level === level);
  const others = dialogues.filter(d => d.level !== level);
  const [selected, setSelected] = useState<Dialogue | null>(null);

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'en-US';
    window.speechSynthesis.speak(utterance);
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <h2 className="text-3xl font-bold">Dialogje për nivelin {level}</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {filtered.map(d => (
          <div key={d.id} onClick={() => setSelected(d)} className="cursor-pointer bg-white bg-opacity-10 p-6 rounded-2xl border-2 border-indigo-400 hover:bg-opacity-20 transition-all group">
            <h3 className="font-black text-xl mb-2 group-hover:text-indigo-400">{d.title}</h3>
            <p className="text-sm opacity-60 line-clamp-2 italic">{d.content}</p>
          </div>
        ))}
      </div>
      {others.length > 0 && (
        <>
          <h3 className="text-xl font-bold opacity-40 mt-12">Eksploro nivele të tjera</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 opacity-40 hover:opacity-100 transition-opacity">
            {others.map(d => (
              <div key={d.id} onClick={() => setSelected(d)} className="cursor-pointer bg-white bg-opacity-10 p-4 rounded-xl border border-white border-opacity-10">
                <h3 className="font-bold text-sm">{d.title} <span className="text-[10px] bg-gray-600 px-1 rounded ml-1">{d.level}</span></h3>
              </div>
            ))}
          </div>
        </>
      )}
      {selected && (
        <div className="fixed inset-0 bg-black bg-opacity-80 backdrop-blur-md flex items-center justify-center p-4 z-50">
          <div className="bg-white text-gray-900 p-10 rounded-3xl max-w-2xl w-full shadow-2xl relative animate-in zoom-in-95 duration-200">
            <button onClick={() => setSelected(null)} className="absolute top-6 right-6 text-gray-300 hover:text-red-500"><i className="fas fa-times text-2xl"></i></button>
            <h3 className="text-3xl font-black mb-6 text-indigo-600">{selected.title}</h3>
            <div className="bg-indigo-50 p-8 rounded-2xl italic whitespace-pre-wrap mb-8 text-xl font-serif leading-relaxed border-l-8 border-indigo-400">
              {selected.content}
            </div>
            <button onClick={() => speak(selected.content)} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black uppercase flex items-center justify-center gap-3 shadow-lg hover:bg-indigo-700">
              <i className="fas fa-volume-up text-2xl"></i> Dëgjo Prononcimin
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

const GamesView: React.FC<{ onWin: (p: number) => void, level: Proficiency }> = ({ onWin, level }) => {
  const [active, setActive] = useState<string | null>(null);
  if (active === 'wordle') return <div className="p-4"><button onClick={() => setActive(null)} className="mb-6 flex items-center gap-2 font-bold text-indigo-400"><i className="fas fa-arrow-left"></i> Kthehu</button><Wordle onWin={onWin} level={level} /></div>;
  if (active === 'hangman') return <div className="p-4"><button onClick={() => setActive(null)} className="mb-6 flex items-center gap-2 font-bold text-indigo-400"><i className="fas fa-arrow-left"></i> Kthehu</button><Hangman onWin={onWin} level={level} /></div>;
  if (active === 'builder') return <div className="p-4"><button onClick={() => setActive(null)} className="mb-6 flex items-center gap-2 font-bold text-indigo-400"><i className="fas fa-arrow-left"></i> Kthehu</button><SentenceBuilder onWin={onWin} level={level} /></div>;
  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-6xl mx-auto py-8">
      <GameCard icon="border-all" color="bg-indigo-600" title="Wordle" points={50} onClick={() => setActive('wordle')} />
      <GameCard icon="skull" color="bg-red-600" title="Hangman" points={30} onClick={() => setActive('hangman')} />
      <GameCard icon="align-left" color="bg-green-600" title="Sentence Builder" points={20} onClick={() => setActive('builder')} />
    </div>
  );
};

const GameCard: React.FC<{ icon: string, color: string, title: string, points: number, onClick: () => void }> = ({ icon, color, title, points, onClick }) => (
  <div onClick={onClick} className="bg-white bg-opacity-10 rounded-3xl overflow-hidden cursor-pointer hover:scale-105 transition-all shadow-xl border border-white border-opacity-5 group">
    <div className={`${color} p-12 flex items-center justify-center text-6xl text-white group-hover:scale-110 transition-transform`}>
      <i className={`fas fa-${icon}`}></i>
    </div>
    <div className="p-8 text-center">
      <h3 className="text-2xl font-black mb-2">{title}</h3>
      <span className="bg-yellow-500 text-black px-4 py-1 rounded-full text-xs font-black uppercase">+{points} PIKË</span>
    </div>
  </div>
);

const LeaderboardView: React.FC<{ users: User[] }> = ({ users }) => {
  const sorted = [...users].sort((a, b) => b.points - a.points);
  return (
    <div className="max-w-3xl mx-auto">
      <div className="text-center mb-12">
        <i className="fas fa-trophy text-6xl text-yellow-400 mb-4 animate-pulse"></i>
