const ChatView: React.FC<{ level: Proficiency }> = ({ level }) => {
  const [messages, setMessages] = useState<{ role: string, text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[75vh] max-w-5xl mx-auto bg-white bg-opacity-10 rounded-3xl overflow-hidden border border-white border-opacity-10 backdrop-blur-md shadow-2xl">
      <div className="p-6 bg-indigo-600 bg-opacity-50 border-b border-white border-opacity-10 flex items-center gap-4">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-indigo-600 text-2xl"><i className="fas fa-robot"></i></div>
        <div>
          <h2 className="font-black uppercase tracking-widest">Mësuesi Virtual AI</h2>
          <p className="text-xs opacity-70">Përshtatur për nivelin tuaj: {level}</p>
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-8 space-y-6">
        {messages.length === 0 && <p className="text-center p-20 opacity-30 italic font-serif text-lg">Bëni një pyetje rreth gramatikës ose fjalorit...</p>}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`p-5 rounded-3xl max-w-[85%] shadow-lg ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white bg-opacity-20 backdrop-blur-sm rounded-tl-none border border-white border-opacity-10'}`}>
              <p className="text-lg leading-relaxed">{m.text}</p>
            </div>
          </div>
        ))}
        {loading && <div className="flex gap-2 p-4 animate-pulse"><div className="w-2 h-2 bg-indigo-400 rounded-full"></div><div className="w-2 h-2 bg-indigo-400 rounded-full"></div><div className="w-2 h-2 bg-indigo-400 rounded-full"></div></div>}
      </div>
      <div className="p-6 bg-black bg-opacity-20 flex gap-4">
        <input 
          className="flex-1 bg-white bg-opacity-5 rounded-2xl px-6 py-4 border border-white border-opacity-10 outline-none focus:ring-2 focus:ring-indigo-500 text-lg" 
          placeholder="Pyet Mësuesin..." 
          value={input} 
          onChange={e => setInput(e.target.value)} 
          onKeyPress={e => e.key === 'Enter' && send()} 
        />
        <button onClick={send} className="bg-indigo-600 w-16 h-16 rounded-2xl font-black shadow-xl hover:bg-indigo-700 transition-all flex items-center justify-center"><i className="fas fa-paper-plane text-2xl"></i></button>
      </div>
    </div>
  );
};

