          <div className="flex flex-col items-center">
            <span className="text-xs uppercase opacity-50 mb-1">Nga</span>
            <span className="font-black text-xl">{fromAlbanian ? 'Shqip' : 'Anglisht'}</span>
          </div>
          <button onClick={() => setFromAlbanian(!fromAlbanian)} className="w-12 h-12 rounded-full bg-indigo-500 flex items-center justify-center hover:rotate-180 transition-all duration-500 shadow-lg">
            <i className="fas fa-exchange-alt"></i>
          </button>
          <div className="flex flex-col items-center">
            <span className="text-xs uppercase opacity-50 mb-1">Te</span>
            <span className="font-black text-xl">{fromAlbanian ? 'Anglisht' : 'Shqip'}</span>
          </div>
        </div>
        <textarea 
          className="w-full p-6 rounded-2xl bg-white bg-opacity-5 border border-white border-opacity-20 min-h-[180px] outline-none text-lg resize-none placeholder-gray-400" 
          placeholder="Shkruani fjalën ose fjalinë këtu..." 
          value={text} 
          onChange={e => setText(e.target.value)} 
        />
        <button 
          onClick={handleTranslate} 
          disabled={loading}
          className="w-full mt-4 bg-indigo-500 py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-xl flex items-center justify-center gap-3"
        >
          {loading ? <i className="fas fa-circle-notch fa-spin"></i> : <><i className="fas fa-magic"></i> Përkthe</>}
        </button>
