  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[75vh] max-w-5xl mx-auto bg-white bg-opacity-10 rounded-3xl overflow-hidden border border-white border-opacity-10 backdrop-blur-md shadow-2xl">
