import { GoogleGenAI } from "@google/genai";
import { Proficiency } from "../types";

// Always initialize GoogleGenAI with a named parameter using process.env.API_KEY
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const translateText = async (text: string, fromAlbanian: boolean) => {
  const ai = getAI();
  const targetLang = fromAlbanian ? "English" : "Albanian";
  const sourceLang = fromAlbanian ? "Albanian" : "English";

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following ${sourceLang} word or sentence to ${targetLang}: "${text}". Only return the translation, no extra text.`,
  });

  return response.text || "Gabim në përkthim.";
};

export const chatWithAI = async (message: string, proficiency: Proficiency = 'Beginner') => {
  const ai = getAI();
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `Ti je një mësues ndihmës i gjuhës Angleze për studentët Shqiptarë. Niveli i studentit është: ${proficiency}. Përshtat gjuhën dhe kompleksitetin tënd sipas këtij niveli. Përgjigju në Shqip kur shpjegon rregulla, por inkurajo përdorimin e Anglishtes. Je miqësor dhe edukativ.`,
    },
  });

  const response = await chat.sendMessage({ message });
  return response.text || "Më vjen keq, nuk munda të përgjigjem.";
};

export const generateWord = async (difficulty: 'easy' | 'medium' | 'hard' = 'medium') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate one common English word for a learning game (difficulty: ${difficulty}). Return ONLY the word in uppercase.`,
  });
  return response.text?.trim().toUpperCase() || "ENGLISH";
};

export const generateSentence = async (level: Proficiency = 'Beginner') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate one simple English sentence for a learning exercise for a ${level} student. Return ONLY the sentence.`,
  });
  return response.text?.trim() || "The cat is on the mat.";
};

