                <button onClick={() => onLogin({ name: formData.name, email: formData.email, provider: 'email', isAdmin: false })} className="w-full bg-black text-white py-3 rounded-lg font-bold hover:bg-gray-800 transition-all">Vazhdo</button>
                <button onClick={() => setStudentMethod('none')} className="w-full text-xs text-gray-500">Kthehu mbrapa</button>
