const PerkthimView: React.FC<{ onTranslate: () => void }> = ({ onTranslate }) => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlb, setFromAlb] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlb);
    setResult(res);
    onTranslate();
    setLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto py-10 space-y-10">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-bold tracking-tight">Përkthim i Mençur</h2>
        <p className="text-gray-500">Mjeti i parë për të pasuruar fjalorin tuaj</p>
      </div>

      <div className="bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden">
        <div className="flex bg-gray-50 border-b border-gray-200 p-4 items-center justify-between">
          <span className="text-xs font-black uppercase text-gray-400 tracking-widest">{fromAlb ? 'Shqip' : 'Anglisht'}</span>
          <button onClick={() => setFromAlb(!fromAlb)} className="w-10 h-10 rounded-full hover:bg-gray-200 transition-all text-gray-500">
            <i className="fas fa-exchange-alt"></i>
          </button>
          <span className="text-xs font-black uppercase text-gray-400 tracking-widest">{fromAlb ? 'Anglisht' : 'Shqip'}</span>
        </div>
        <textarea 
          className="w-full p-6 h-48 outline-none text-xl font-medium bg-transparent placeholder-gray-300 resize-none"
          placeholder="Shkruani fjalët..."
          value={text}
          onChange={e => setText(e.target.value)}
        />
        <div className="p-4 bg-gray-50 flex justify-end">
          <button onClick={handleTranslate} className="bg-black text-white px-8 py-3 rounded-xl font-bold hover:opacity-90 disabled:opacity-50 transition-all">
            {loading ? <i className="fas fa-spinner fa-spin"></i> : 'Përkthe'}
          </button>
        </div>
      </div>

      {result && (
        <div className="bg-indigo-50 border border-indigo-100 p-8 rounded-2xl animate-in fade-in slide-in-from-top-4">
          <p className="text-[10px] uppercase font-bold text-indigo-400 mb-2">Përkthimi</p>
          <p className="text-3xl font-bold text-indigo-900">{result}</p>
        </div>
      )}
    </div>
  );
};

const ChatView: React.FC<{ level: Proficiency }> = ({ level }) => {
  const [messages, setMessages] = useState<{ role: string, text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] max-w-4xl mx-auto">
      <div className="flex-1 overflow-y-auto p-4 space-y-8 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-40">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center text-2xl">
              <i className="fas fa-robot"></i>
            </div>
            <h3 className="text-xl font-bold">Unë jam mësuesi juaj virtual</h3>
            <p className="max-w-xs text-sm">Më pyet për çdo gjë rreth Anglishtes. Unë do të përshtatem me nivelin tënd {level}.</p>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex gap-4 ${m.role === 'model' ? 'bg-gray-50 -mx-4 px-4 py-8 rounded-2xl' : ''}`}>
             <div className={`w-8 h-8 rounded-md flex items-center justify-center flex-shrink-0 text-white font-bold text-xs ${m.role === 'user' ? 'bg-indigo-600' : 'bg-green-600'}`}>
               {m.role === 'user' ? 'U' : 'AI'}
             </div>
             <div className="flex-1 text-base leading-relaxed whitespace-pre-wrap">
               {m.text}
             </div>
          </div>
        ))}
        {loading && <div className="animate-pulse text-gray-400 italic">Mësuesi po shkruan...</div>}
      </div>

      <div className="mt-4 p-4 border border-gray-200 rounded-2xl bg-white shadow-sm flex items-end gap-2">
        <textarea 
          rows={1}
          className="flex-1 p-2 bg-transparent outline-none text-base resize-none max-h-32"
          placeholder="Dërgo një mesazh..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), send())}
        />
        <button onClick={send} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${input.trim() ? 'bg-black text-white' : 'bg-gray-100 text-gray-300'}`}>
          <i className="fas fa-arrow-up"></i>
        </button>
      </div>
      <p className="text-[10px] text-gray-400 text-center mt-2">AI mund të bëjë gabime. Kontrollo informacionin e rëndësishëm.</p>
    </div>
  );
};

