                    {!u.isAdmin && (
                      <button onClick={() => {
                        const pass = prompt("Fjalëkalimi i ri për adminin:");
                        if (pass) onMakeAdmin(u.id, pass);
                      }} className="text-[10px] font-bold text-indigo-600 hover:underline">Promovo</button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {tab === 'dialogues' && (
        <div className="bg-white border border-gray-200 p-8 rounded-2xl space-y-4">
          <input className="w-full p-4 border border-gray-200 rounded-xl outline-none" placeholder="Titulli" value={newD.title} onChange={e => setNewD({...newD, title: e.target.value})} />
          <textarea className="w-full p-4 border border-gray-200 rounded-xl outline-none h-32" placeholder="Përmbajtja (A: / B:)" value={newD.content} onChange={e => setNewD({...newD, content: e.target.value})} />
          <select className="w-full p-4 border border-gray-200 rounded-xl" value={newD.level} onChange={e => setNewD({...newD, level: e.target.value as Proficiency})}>
            <option>Beginner</option><option>Intermediate</option><option>Advanced</option>
          </select>
          <button onClick={() => onDialogueAdd({ id: Date.now().toString(), ...newD, addedBy: 'Admin' })} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Publiko</button>
        </div>
      )}

      {tab === 'suggestions' && (
        <div className="space-y-4">
          {suggestions.map(s => (
            <div key={s.id} className="bg-white border border-gray-200 p-6 rounded-2xl shadow-sm">
