import { Wordle, Hangman, SentenceBuilder } from './components/Games';

const INITIAL_DIALOGUES: Dialogue[] = [
  { id: '1', title: 'Daily Greetings', content: 'A: Hello! How are you?\nB: I am fine, thank you.', addedBy: 'Admin', level: 'Beginner' },
  { id: '2', title: 'Business Strategy', content: 'A: Let\'s review the quarterly results.\nB: Certainly, the growth is steady.', addedBy: 'Admin', level: 'Advanced' }
];

const NavLink: React.FC<{ to: string; icon: string; children: React.ReactNode; highlight?: boolean; onClick?: () => void }> = ({ to, icon, children, highlight, onClick }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link 
      to={to} 
      onClick={onClick}
      className={`w-full group flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors duration-200 ${
        isActive 
          ? 'bg-[#ececec] text-black shadow-sm' 
          : 'text-[#676767] hover:bg-[#ececec] hover:text-black'
      } ${highlight ? 'text-indigo-600 font-semibold' : ''}`}
    >
      <i className={`fas fa-${icon} w-5 text-center text-sm ${isActive ? 'text-black' : 'text-[#676767] group-hover:text-black'}`}></i>
      <span className="text-[14px] font-medium">{children}</span>
    </Link>
  );
};

const App: React.FC = () => {
  const [theme, setTheme] = useState<ThemeColor>('default');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [dialogues, setDialogues] = useState<Dialogue[]>(INITIAL_DIALOGUES);
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('app_theme') as ThemeColor;
    if (savedTheme) setTheme(savedTheme);
    setAllUsers(JSON.parse(localStorage.getItem('app_users') || '[]'));
    setDialogues(JSON.parse(localStorage.getItem('app_dialogues') || JSON.stringify(INITIAL_DIALOGUES)));
    setSuggestions(JSON.parse(localStorage.getItem('app_suggestions') || '[]'));
  }, []);

  useEffect(() => {
    localStorage.setItem('app_theme', theme);
    localStorage.setItem('app_users', JSON.stringify(allUsers));
    localStorage.setItem('app_dialogues', JSON.stringify(dialogues));
    localStorage.setItem('app_suggestions', JSON.stringify(suggestions));
  }, [theme, allUsers, dialogues, suggestions]);

  const login = (data: { name: string; email?: string; password?: string; provider: AuthProvider; isAdmin: boolean }) => {
    let user = allUsers.find(u => 
      (data.email && u.email === data.email) || 
      (!data.email && u.name.toLowerCase() === data.name.toLowerCase())
    );

    if (data.isAdmin) {
      if (user && user.password !== data.password) {
        alert("Fjalëkalim i pasaktë.");
        return;
      }
      if (!user) {
        user = { 
          id: Date.now().toString(), 
          name: data.name, 
          isAdmin: true, 
          streak: 1, 
          lastLogin: new Date().toISOString(),
          points: 0,
          badges: [],
          authProvider: 'admin',
          password: data.password
        };
        setAllUsers([...allUsers, user]);
      }
    } else {
      if (!user) {
        user = { 
          id: Date.now().toString(), 
          name: data.name, 
          email: data.email,
          isAdmin: false, 
          streak: 1, 
          lastLogin: new Date().toISOString(),
          points: 0,
          badges: [],
          authProvider: data.provider
        };
        setAllUsers([...allUsers, user]);
      }
    }

    const today = new Date().toDateString();
    const last = new Date(user!.lastLogin).toDateString();
    if (today !== last) {
      user!.streak += 1;
      user!.lastLogin = new Date().toISOString();
      setAllUsers(allUsers.map(u => u.id === user?.id ? user! : u));
    }

    setCurrentUser(user!);
  };

  const addPoints = (amount: number) => {
    if (!currentUser) return;
    const updated = { ...currentUser, points: currentUser.points + amount };
    if (updated.points >= 100 && !updated.badges.includes('Learner')) updated.badges.push('Learner');
    if (updated.points >= 500 && !updated.badges.includes('Scholar')) updated.badges.push('Scholar');

    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const updateProfile = (proficiency: Proficiency, goal: Goal) => {
    if (!currentUser) return;
    const updated = { ...currentUser, proficiency, goal };
    setCurrentUser(updated);
    setAllUsers(allUsers.map(u => u.id === updated.id ? updated : u));
  };

  const logout = () => {
    setCurrentUser(null);
    setIsSidebarOpen(false);
  };

  if (!currentUser) return <LoginScreen onLogin={login} />;
  if (!currentUser.proficiency && !currentUser.isAdmin) return <ProfileSetup onSave={updateProfile} />;

  const SidebarContent = () => (
    <>
      <div className="p-3">
        <Link to="/" onClick={() => setIsSidebarOpen(false)} className="flex items-center gap-3 w-full px-3 py-3 rounded-lg border border-[#e5e5e5] hover:bg-[#ececec] transition-all text-black mb-6">
          <i className="fas fa-plus text-xs"></i>
          <span className="text-sm font-semibold">Sesion i ri</span>
        </Link>
      </div>

      <nav className="flex-1 px-3 space-y-1 overflow-y-auto custom-scrollbar">
        <div className="text-[10px] uppercase font-bold text-gray-400 px-3 mb-2 tracking-wider">Shërbimet</div>
        <NavLink to="/" icon="language" onClick={() => setIsSidebarOpen(false)}>Përkthim</NavLink>
        <NavLink to="/dialogues" icon="book-open" onClick={() => setIsSidebarOpen(false)}>Dialogje</NavLink>
        <NavLink to="/games" icon="gamepad" onClick={() => setIsSidebarOpen(false)}>Lojëra</NavLink>
        <NavLink to="/chat" icon="message" onClick={() => setIsSidebarOpen(false)}>AngliBot AI</NavLink>

        <div className="text-[10px] uppercase font-bold text-gray-400 px-3 mt-6 mb-2 tracking-wider">Statistikat</div>
        <NavLink to="/leaderboard" icon="trophy" onClick={() => setIsSidebarOpen(false)}>Renditja</NavLink>
        <NavLink to="/streak" icon="bolt" onClick={() => setIsSidebarOpen(false)}>Streak</NavLink>
        <NavLink to="/suggestions" icon="lightbulb" onClick={() => setIsSidebarOpen(false)}>Sugjerime</NavLink>

        {currentUser.isAdmin && (
          <>
            <div className="text-[10px] uppercase font-bold text-indigo-500 px-3 mt-6 mb-2 tracking-wider">Admin</div>
            <NavLink to="/admin" icon="shield-halved" highlight onClick={() => setIsSidebarOpen(false)}>Admin Panel</NavLink>
          </>
        )}
      </nav>

      <div className="p-3 border-t border-[#e5e5e5]">
        <NavLink to="/settings" icon="gear" onClick={() => setIsSidebarOpen(false)}>Cilësimet</NavLink>
        <div className="flex items-center gap-3 p-3 mt-2 rounded-lg hover:bg-[#ececec] cursor-pointer transition-all group" onClick={logout}>
          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-500">
            <i className="fas fa-arrow-right-from-bracket"></i>
          </div>
          <span className="text-sm font-medium text-black">Dilni</span>
        </div>
      </div>
    </>
  );

  return (
    <HashRouter>
      <div className="flex h-screen overflow-hidden bg-white text-black font-sans">
        {/* Desktop Sidebar */}
        <aside className="w-[260px] bg-[#f9f9f9] flex-shrink-0 flex flex-col hidden md:flex border-r border-[#e5e5e5]">
          <SidebarContent />
        </aside>

        {/* Mobile Sidebar Overlay */}
        {isSidebarOpen && (
          <div className="fixed inset-0 bg-black/50 z-50 md:hidden" onClick={() => setIsSidebarOpen(false)}>
            <div 
              className="absolute left-0 top-0 bottom-0 w-[280px] bg-[#f9f9f9] flex flex-col animate-in slide-in-from-left duration-300" 
              onClick={(e) => e.stopPropagation()}
            >
              <div className="p-4 flex justify-between items-center border-b border-[#e5e5e5] mb-2">
                <span className="font-bold text-lg">AngliBot AI</span>
                <button onClick={() => setIsSidebarOpen(false)} className="text-gray-500 p-2"><i className="fas fa-times"></i></button>
              </div>
              <SidebarContent />
            </div>
          </div>
        )}

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col relative overflow-hidden">
          {/* Top Bar */}
          <header className="h-14 border-b border-[#e5e5e5] flex items-center justify-between px-4 bg-white/80 backdrop-blur-md sticky top-0 z-40">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 -ml-2 text-gray-500">
                <i className="fas fa-bars"></i>
              </button>
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 bg-black rounded flex items-center justify-center text-white text-xs font-bold">A</div>
                <h1 className="font-bold text-sm tracking-tight">AngliBot AI</h1>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <div className="hidden sm:flex items-center gap-3 bg-[#f4f4f4] px-3 py-1.5 rounded-full border border-[#e5e5e5]">
                <div className="flex items-center gap-1.5">
                  <i className="fas fa-star text-yellow-500 text-[10px]"></i>
                  <span className="text-[11px] font-bold">{currentUser.points}</span>
                </div>
                <div className="w-px h-3 bg-gray-300"></div>
                <div className="flex items-center gap-1.5">
                  <i className="fas fa-fire text-orange-500 text-[10px]"></i>
                  <span className="text-[11px] font-bold">{currentUser.streak}</span>
                </div>
              </div>
              <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center text-xs font-bold">
                {currentUser.name[0].toUpperCase()}
              </div>
            </div>
          </header>

          {/* Content Scroll Area */}
          <div className="flex-1 overflow-y-auto custom-scrollbar">
            <div className="max-w-3xl mx-auto w-full px-4 py-8 md:px-8">
              <Routes>
                <Route path="/" element={<PerkthimView onTranslate={() => addPoints(5)} />} />
                <Route path="/dialogues" element={<DialoguesView dialogues={dialogues} level={currentUser.proficiency || 'Beginner'} />} />
                <Route path="/games" element={<GamesView onWin={addPoints} level={currentUser.proficiency || 'Beginner'} />} />
                <Route path="/leaderboard" element={<LeaderboardView users={allUsers} />} />
                <Route path="/chat" element={<ChatView level={currentUser.proficiency || 'Beginner'} />} />
                <Route path="/streak" element={<StreakView user={currentUser} />} />
                <Route path="/suggestions" element={<SuggestionsView suggestions={suggestions} onAdd={(text) => {
                  setSuggestions([...suggestions, { id: Date.now().toString(), userId: currentUser.id, userName: currentUser.name, text, date: new Date().toLocaleDateString() }]);
                }} />} />
                <Route path="/settings" element={<SettingsView currentTheme={theme} onThemeChange={setTheme} />} />
                {currentUser.isAdmin && (
                  <Route path="/admin" element={
                    <AdminView 
                      users={allUsers} 
                      suggestions={suggestions} 
                      onDialogueAdd={(d) => setDialogues([...dialogues, d])}
                      onMakeAdmin={(id, pass) => setAllUsers(allUsers.map(u => u.id === id ? {...u, isAdmin: !u.isAdmin, password: pass} : u))}
                      onRespondSuggestion={(id, msg) => setSuggestions(suggestions.map(s => s.id === id ? {...s, adminResponse: msg} : s))}
                    />
                  } />
                )}
              </Routes>
            </div>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

