              <input type="password" placeholder="Fjalëkalimi" className="w-full px-4 py-3 border border-[#d2d2d7] rounded-lg focus:outline-none focus:ring-1 focus:ring-black text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
              <button onClick={() => onLogin({ name: formData.name, password: formData.password, provider: 'admin', isAdmin: true })} className="w-full bg-black text-white py-3 rounded-lg font-bold hover:opacity-90 transition-all text-sm">Hyr si Admin</button>
