const PerkthimView: React.FC<{ onTranslate: () => void }> = ({ onTranslate }) => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlb, setFromAlb] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlb);
    setResult(res);
    onTranslate();
    setLoading(false);
  };

  return (
    <div className="space-y-8 max-w-2xl mx-auto">
      <div className="space-y-2">
        <h2 className="text-2xl font-bold tracking-tight">Përkthim</h2>
        <p className="text-[#6e6e73] text-sm">Përktheni shpejt midis Shqipes dhe Anglishtes.</p>
      </div>

      <div className="bg-[#f5f5f7] border border-[#e5e5e5] rounded-2xl overflow-hidden">
        <div className="flex bg-white border-b border-[#e5e5e5] p-3 items-center justify-between">
          <span className="text-[11px] font-bold uppercase text-[#86868b] tracking-widest px-2">{fromAlb ? 'Shqip' : 'Anglisht'}</span>
          <button onClick={() => setFromAlb(!fromAlb)} className="w-8 h-8 rounded-full hover:bg-[#f5f5f7] transition-all text-[#6e6e73]">
            <i className="fas fa-exchange-alt text-xs"></i>
          </button>
          <span className="text-[11px] font-bold uppercase text-[#86868b] tracking-widest px-2">{fromAlb ? 'Anglisht' : 'Shqip'}</span>
        </div>
        <textarea 
          className="w-full p-6 h-40 outline-none text-lg font-medium bg-transparent placeholder-gray-400 resize-none"
          placeholder="Shkruani tekstin këtu..."
          value={text}
          onChange={e => setText(e.target.value)}
        />
        <div className="p-4 bg-white border-t border-[#e5e5e5] flex justify-end">
          <button onClick={handleTranslate} className="bg-black text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:opacity-90 disabled:opacity-50 transition-all">
            {loading ? <i className="fas fa-circle-notch fa-spin"></i> : 'Përkthe'}
          </button>
        </div>
      </div>

      {result && (
        <div className="bg-white border border-[#e5e5e5] p-6 rounded-2xl animate-in fade-in slide-in-from-top-2">
          <p className="text-[10px] uppercase font-bold text-[#86868b] mb-2 tracking-widest">Rezultati</p>
          <p className="text-2xl font-bold leading-tight">{result}</p>
        </div>
      )}
    </div>
  );
};

const ChatView: React.FC<{ level: Proficiency }> = ({ level }) => {
  const [messages, setMessages] = useState<{ role: string, text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] max-w-2xl mx-auto">
      <div className="flex-1 overflow-y-auto p-2 space-y-8 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 py-20">
            <div className="w-16 h-16 bg-black text-white rounded-2xl flex items-center justify-center text-3xl shadow-xl">
              <i className="fas fa-robot"></i>
            </div>
            <div className="space-y-2">
              <h3 className="text-xl font-bold">Unë jam AngliBot</h3>
              <p className="max-w-xs text-sm text-[#6e6e73] leading-relaxed">Si mund t'ju ndihmoj me Anglishten tuaj sot? Mund të bisedojmë për çdo temë që dëshironi.</p>
            </div>
            <div className="grid grid-cols-1 gap-2 w-full max-w-sm">
              <button onClick={() => setInput("Më trego një fakt interesant në Anglisht.")} className="text-xs border border-[#e5e5e5] p-3 rounded-xl hover:bg-[#f5f5f7] transition-all text-left">"Më trego një fakt interesant..."</button>
              <button onClick={() => setInput("Si mund të përmirësoj prononcimin tim?")} className="text-xs border border-[#e5e5e5] p-3 rounded-xl hover:bg-[#f5f5f7] transition-all text-left">"Si të përmirësoj prononcimin?"</button>
            </div>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex gap-5 py-2 ${m.role === 'model' ? 'bg-[#f7f7f8] -mx-4 px-4 py-8 rounded-2xl' : ''}`}>
             <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 text-white font-bold text-[10px] shadow-sm ${m.role === 'user' ? 'bg-indigo-600' : 'bg-black'}`}>
               {m.role === 'user' ? 'U' : <i className="fas fa-robot"></i>}
             </div>
             <div className="flex-1 text-[15px] leading-relaxed whitespace-pre-wrap font-medium">
               {m.text}
             </div>
          </div>
        ))}
        {loading && <div className="flex gap-4 p-2 items-center text-[#86868b] text-sm italic animate-pulse">
           <div className="w-8 h-8 rounded-lg bg-black text-white flex items-center justify-center text-[10px]"><i className="fas fa-robot"></i></div>
           <span>AngliBot po mendon...</span>
        </div>}
      </div>

      <div className="mt-8 relative group">
