const AdminView: React.FC<{ 
  users: User[], 
  suggestions: Suggestion[], 
  onDialogueAdd: (d: Dialogue) => void,
  onMakeAdmin: (id: string, pass: string) => void,
  onRespondSuggestion: (id: string, msg: string) => void
}> = ({ users, suggestions, onDialogueAdd, onMakeAdmin, onRespondSuggestion }) => {
  const [tab, setTab] = useState('users');
  const [newD, setNewD] = useState({ title: '', content: '', level: 'Beginner' as Proficiency, audioData: '' });
  const [resp, setResp] = useState<{[k: string]: string}>({});
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewD({ ...newD, audioData: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div className="flex gap-4 border-b border-[#e5e5e5]">
        {['users', 'dialogues', 'suggestions'].map(t => (
          <button key={t} onClick={() => setTab(t)} className={`pb-3 text-xs font-bold uppercase tracking-widest transition-all ${tab === t ? 'border-b-2 border-black text-black' : 'text-[#86868b] hover:text-black'}`}>{t === 'users' ? 'Përdoruesit' : t === 'dialogues' ? 'Dialogjet' : 'Sugjerimet'}</button>
        ))}
      </div>

      {tab === 'users' && (
        <div className="bg-white border border-[#e5e5e5] rounded-xl overflow-hidden shadow-sm">
          <table className="w-full text-left text-xs">
            <thead className="bg-[#f5f5f7]">
