          <textarea className="w-full p-4 border border-[#d2d2d7] rounded-xl text-sm h-32 bg-white resize-none" placeholder="Përmbajtja (A: / B:)" value={newD.content} onChange={e => setNewD({...newD, content: e.target.value})} />
          <select className="w-full p-4 border border-[#d2d2d7] rounded-xl text-sm bg-white" value={newD.level} onChange={e => setNewD({...newD, level: e.target.value as Proficiency})}>
