            <input type="file" accept="audio/*" ref={fileInputRef} onChange={handleAudioUpload} className="w-full text-xs" />
            {newD.audioData && <p className="text-[10px] text-green-600 font-bold italic"><i className="fas fa-check"></i> Audio u ngarkua me sukses</p>}
          </div>
          <button onClick={() => { if(newD.title && newD.content){ onDialogueAdd({ id: Date.now().toString(), ...newD, addedBy: 'Admin' }); setNewD({title:'', content:'', level:'Beginner', audioData:''}); if(fileInputRef.current) fileInputRef.current.value = ""; alert("Dialogu u shtua!"); } }} className="bg-black text-white px-8 py-3 rounded-xl font-bold text-sm w-full shadow-lg hover:opacity-90">Publiko Dialogun</button>
        </div>
      )}

      {tab === 'suggestions' && (
        <div className="space-y-4">
          {suggestions.length === 0 && <p className="text-center py-10 text-gray-400 text-sm italic">Nuk ka sugjerime për momentin.</p>}
          {suggestions.map(s => (
            <div key={s.id} className="p-5 border border-[#e5e5e5] rounded-xl bg-white shadow-sm">
              <p className="text-sm font-bold mb-3">{s.userName}: <span className="font-normal text-gray-600">{s.text}</span></p>
              {!s.adminResponse ? (
                <div className="flex gap-2">
                  <input className="flex-1 p-2 bg-[#f5f5f7] border border-[#d2d2d7] rounded-lg text-xs outline-none focus:border-black" placeholder="Përgjigju..." value={resp[s.id] || ''} onChange={e => setResp({...resp, [s.id]: e.target.value})} />
                  <button onClick={() => { if(resp[s.id]){ onRespondSuggestion(s.id, resp[s.id]); alert("Përgjigja u dërgua!"); } }} className="bg-black text-white px-4 rounded-lg text-xs font-bold">Dërgo</button>
                </div>
              ) : <p className="text-[10px] italic text-[#86868b] border-l-2 border-green-500 pl-2">Përgjigjur.</p>}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

