];

// Predefined admin account 'User' with password '123admin' as requested
const PREDEFINED_ADMINS: User[] = [
  { id: 'admin-user', name: 'User', isAdmin: true, password: '123admin', streak: 1, lastLogin: new Date().toISOString(), points: 0, badges: [] },
  { id: 'admin1', name: 'Admin1', isAdmin: true, password: '123admin', streak: 1, lastLogin: new Date().toISOString(), points: 0, badges: [] },
