const PerkthimView: React.FC<{ onTranslate: () => void, isDark?: boolean }> = ({ onTranslate, isDark }) => {
  const [text, setText] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [fromAlb, setFromAlb] = useState(true);

  const handleTranslate = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const res = await translateText(text, fromAlb);
    setResult(res);
    onTranslate();
    setLoading(false);
  };

  return (
    <div className="space-y-8 max-w-2xl mx-auto">
      <div className="space-y-2">
        <h2 className="text-2xl font-bold tracking-tight">Përkthim</h2>
        <p className={`${isDark ? 'text-zinc-400' : 'text-[#6e6e73]'} text-sm`}>Përktheni shpejt midis Shqipes dhe Anglishtes.</p>
      </div>

      <div className={`${isDark ? 'bg-zinc-900 border-zinc-800' : 'bg-[#f5f5f7] border-[#e5e5e5]'} border rounded-2xl overflow-hidden shadow-sm`}>
        <div className={`flex border-b p-3 items-center justify-between ${isDark ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-[#e5e5e5]'}`}>
          <span className={`text-[11px] font-bold uppercase tracking-widest px-2 ${isDark ? 'text-zinc-500' : 'text-[#86868b]'}`}>{fromAlb ? 'Shqip' : 'Anglisht'}</span>
          <button onClick={() => setFromAlb(!fromAlb)} className={`w-8 h-8 rounded-full transition-all ${isDark ? 'hover:bg-zinc-800 text-zinc-500' : 'hover:bg-[#f5f5f7] text-[#6e6e73]'}`}>
            <i className="fas fa-exchange-alt text-xs"></i>
          </button>
          <span className={`text-[11px] font-bold uppercase tracking-widest px-2 ${isDark ? 'text-zinc-500' : 'text-[#86868b]'}`}>{fromAlb ? 'Anglisht' : 'Shqip'}</span>
        </div>
        <textarea className={`w-full p-6 h-40 outline-none text-lg font-medium bg-transparent placeholder-zinc-500 resize-none`} placeholder="Shkruani tekstin këtu..." value={text} onChange={e => setText(e.target.value)} />
        <div className={`p-4 border-t flex justify-end ${isDark ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-[#e5e5e5]'}`}>
          <button onClick={handleTranslate} className="bg-black text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:opacity-90 disabled:opacity-50 transition-all shadow-md border border-zinc-700">
            {loading ? <i className="fas fa-circle-notch fa-spin"></i> : 'Përkthe'}
          </button>
        </div>
      </div>

      {result && (
        <div className={`border p-6 rounded-2xl animate-in fade-in slide-in-from-top-2 shadow-sm ${isDark ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-[#e5e5e5]'}`}>
          <p className={`text-[10px] uppercase font-bold mb-2 tracking-widest ${isDark ? 'text-zinc-500' : 'text-[#86868b]'}`}>Rezultati</p>
          <p className="text-2xl font-bold leading-tight">{result}</p>
        </div>
      )}
    </div>
  );
};

const ChatView: React.FC<{ level: Proficiency, isDark?: boolean }> = ({ level, isDark }) => {
  const [messages, setMessages] = useState<{ role: string, text: string }[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const msg = input; setInput('');
    setMessages(prev => [...prev, { role: 'user', text: msg }]);
    setLoading(true);
    const res = await chatWithAI(msg, level);
    setMessages(prev => [...prev, { role: 'model', text: res }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] max-w-2xl mx-auto">
      <div className="flex-1 overflow-y-auto p-2 space-y-8 custom-scrollbar">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center space-y-6 py-20">
            <img src={LOGO_URL} alt="Logo" className={`w-20 h-20 grayscale brightness-0 opacity-20 ${isDark ? 'invert' : ''}`} />
            <div className="space-y-2">
              <h3 className="text-xl font-bold">Unë jam AngliBot</h3>
              <p className={`max-w-xs text-sm leading-relaxed ${isDark ? 'text-zinc-400' : 'text-[#6e6e73]'}`}>Si mund t'ju ndihmoj me Anglishten tuaj sot?</p>
            </div>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex gap-5 py-2 ${m.role === 'model' ? (isDark ? 'bg-zinc-900/50 -mx-4 px-4 py-8 rounded-2xl' : 'bg-[#f7f7f8] -mx-4 px-4 py-8 rounded-2xl') : ''}`}>
             <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 text-white font-bold text-[10px] shadow-sm ${m.role === 'user' ? 'bg-indigo-600' : 'bg-black'}`}>
               {m.role === 'user' ? 'U' : <i className="fas fa-robot"></i>}
             </div>
             <div className="flex-1 text-[15px] font-medium leading-relaxed whitespace-pre-wrap">
               {m.text}
             </div>
          </div>
        ))}
        {loading && <div className="flex gap-4 p-2 items-center text-[#86868b] text-sm italic animate-pulse">
           <div className="w-8 h-8 rounded-lg bg-black text-white flex items-center justify-center text-[10px]"><i className="fas fa-robot"></i></div>
           <span>AngliBot po mendon...</span>
        </div>}
      </div>

      <div className="mt-8 relative group">
        <div className={`absolute inset-0 blur-xl group-focus-within:bg-black/10 transition-all rounded-3xl ${isDark ? 'bg-zinc-800/10' : 'bg-black/5'}`}></div>
        <div className={`relative p-3 border rounded-2xl shadow-sm flex items-end gap-3 transition-all ${isDark ? 'bg-zinc-900 border-zinc-800 focus-within:border-zinc-600' : 'bg-white border-[#d2d2d7] focus-within:border-black'}`}>
          <textarea rows={1} className="flex-1 p-2 bg-transparent outline-none text-[15px] font-medium resize-none max-h-32 min-h-[44px]" placeholder="Dërgo mesazh..." value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), send())} />
          <button onClick={send} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${input.trim() ? 'bg-black text-white border border-zinc-700' : (isDark ? 'bg-zinc-800 text-zinc-600' : 'bg-[#e5e5e5] text-white')} cursor-not-allowed`}>
            <i className="fas fa-arrow-up text-sm"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

