            <div className="flex flex-col sm:flex-row gap-5">
              {selected.audioData && (
                <button onClick={() => playAudio(selected.audioData!)} className="flex-1 bg-indigo-600 text-white py-5 rounded-2xl font-black text-sm flex items-center justify-center gap-3 shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">
                  <i className="fas fa-play"></i> Dëgjo Regjistrimin e Mësuesit
                </button>
              )}
              <button 
                onClick={() => {
                  const utterance = new SpeechSynthesisUtterance(selected.content);
                  utterance.lang = 'en-US';
                  window.speechSynthesis.speak(utterance);
                }}
                className={`py-5 rounded-2xl font-black text-sm flex items-center justify-center gap-3 shadow-xl hover:opacity-90 active:scale-95 transition-all border border-zinc-700 bg-black text-white ${selected.audioData ? 'px-10' : 'w-full'}`}
