            <div className="space-y-1">
              <p className="font-black text-lg">{game.title}</p>
              <p className={`text-[10px] font-bold uppercase tracking-widest leading-tight ${isDark ? 'text-zinc-600' : 'text-gray-400'}`}>{game.desc}</p>
            </div>
          </button>
        ))}
      </div>
