            <h3 className={`font-black text-lg tracking-tight`}>Krijo Përmbajtje të Re</h3>
            <p className="text-[10px] font-bold uppercase text-gray-500 tracking-widest">Shto dialogjet që do të shohin studentët</p>
          </div>
          <div className="space-y-4">
            <input className={`w-full p-5 border rounded-2xl text-sm font-bold outline-none transition-all ${isDark ? 'bg-zinc-900 border-zinc-800 focus:border-zinc-500 text-white' : 'bg-gray-50 border-black/5 focus:border-black'}`} placeholder="Titulli i Dialogut (p.sh. Te Banka)" value={newD.title} onChange={e => setNewD({...newD, title: e.target.value})} />
            <textarea className={`w-full p-6 border rounded-3xl text-sm h-40 resize-none outline-none transition-all font-serif italic ${isDark ? 'bg-zinc-900 border-zinc-700 focus:border-zinc-500 text-white' : 'bg-gray-50 border-black/5 focus:border-black'}`} placeholder="Teksti i Bisedës... (A: / B:)" value={newD.content} onChange={e => setNewD({...newD, content: e.target.value})} />
            <div className="grid grid-cols-2 gap-4">
              <select className={`w-full p-5 border rounded-2xl text-sm font-bold outline-none transition-all ${isDark ? 'bg-zinc-900 border-zinc-700 focus:border-zinc-500 text-white' : 'bg-gray-50 border-black/5 focus:border-black'}`} value={newD.level} onChange={e => setNewD({...newD, level: e.target.value as Proficiency})}>
                <option value="Beginner">Fillestar</option>
                <option value="Intermediate">Mesatar</option>
                <option value="Advanced">I Avancuar</option>
              </select>
              <div className={`relative p-5 border rounded-2xl shadow-inner transition-all ${isDark ? 'bg-zinc-900/50 border-zinc-700' : 'bg-gray-50 border-black/5'}`}>
                <label className={`block text-[9px] font-black uppercase tracking-widest mb-2 ${isDark ? 'text-zinc-600' : 'text-gray-400'}`}>Zëri i regjistruar</label>
                <input type="file" accept="audio/*" ref={fileInputRef} onChange={handleAudioUpload} className="w-full text-[10px] font-bold cursor-pointer file:hidden" />
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none">
                   {newD.audioData ? <i className="fas fa-check-circle text-green-500"></i> : <i className="fas fa-upload text-gray-300"></i>}
                </div>
              </div>
            </div>
          </div>
          <button onClick={() => { if(newD.title && newD.content){ onDialogueAdd({ id: Date.now().toString(), ...newD, addedBy: 'Admin' }); setNewD({title:'', content:'', level:'Beginner', audioData:''}); if(fileInputRef.current) fileInputRef.current.value = ""; alert("Dialogu u publikua me sukses!"); } else { alert("Ju lutem plotësoni titullin dhe përmbajtjen."); } }} className="bg-black text-white px-8 py-5 rounded-[1.5rem] font-black text-sm w-full shadow-2xl hover:opacity-90 active:scale-95 transition-all border border-zinc-700 uppercase tracking-[0.2em]">Publiko në Platformë</button>
        </div>
      )}

      {tab === 'suggestions' && (
        <div className="space-y-6">
          {suggestions.length === 0 && <p className={`text-center py-24 text-sm italic border-4 border-dashed rounded-[3rem] ${isDark ? 'text-zinc-600 border-zinc-900' : 'text-gray-300 border-gray-100'}`}>Nuk ka mesazhe të reja nga studentët.</p>}
          {suggestions.map(s => (
            <div key={s.id} className={`p-8 border rounded-[2.5rem] shadow-2xl transition-all hover:scale-[1.02] ${isDark ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-black/5'}`}>
              <div className="flex justify-between items-center mb-5">
                 <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-2xl bg-indigo-500/10 text-indigo-500 flex items-center justify-center font-black">{s.userName[0]}</div>
                   <p className="text-sm font-black">{s.userName}</p>
                 </div>
                 <span className={`text-[10px] font-black tracking-tighter ${isDark ? 'text-zinc-600' : 'text-gray-400'}`}>{s.date}</span>
              </div>
              <p className={`text-sm mb-6 leading-relaxed font-medium ${isDark ? 'text-zinc-400' : 'text-gray-600'}`}>{s.text}</p>
              {!s.adminResponse ? (
                <div className="flex gap-3">
                  <input className={`flex-1 p-4 border rounded-2xl text-xs font-bold outline-none transition-all ${isDark ? 'bg-zinc-900 border-zinc-700 focus:border-zinc-500' : 'bg-gray-50 border-black/5 focus:border-black shadow-inner'}`} placeholder="Shkruaj një përgjigje..." value={resp[s.id] || ''} onChange={e => setResp({...resp, [s.id]: e.target.value})} />
                  <button onClick={() => { if(resp[s.id]){ onRespondSuggestion(s.id, resp[s.id]); alert("Komentet e tua u dërguan!"); } }} className="bg-black text-white px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:opacity-90 active:scale-90 transition-all border border-zinc-700">Dërgo</button>
                </div>
              ) : (
                <div className={`p-4 rounded-2xl text-[11px] font-bold border-l-4 italic flex items-center gap-3 ${isDark ? 'bg-zinc-800/30 border-green-900 text-zinc-500' : 'bg-green-50 border-green-500 text-green-700'}`}>
                  <i className="fas fa-check-circle text-xs"></i> Keni kthyer përgjigje këtij sugjerimi.
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

